input.command:
# Verify local health
curl -sS --max-time 5 -o /dev/null -w "local=%{http_code}\n" http://127.0.0.1:20128/

# Enable Cloudflare tunnel via 9router's own API client
node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
(async () => {
  const status = await api.getTunnelStatus();
  console.log('status_before', JSON.stringify(status, null, 2));
  const en = await api.enableTunnel();
  console.log('enable', JSON.stringify(en, null, 2));
  const after = await api.getTunnelStatus();
  console.log('status_after', JSON.stringify(after, null, 2));
  // also list API keys if possible
  try {
    const keys = await api.listApiKeys?.() || await api.getApiKeys?.();
    if (keys) console.log('keys', JSON.stringify(keys, null, 2));
  } catch (e) { console.log('keys_err', e.message); }
})().catch(e => { console.error(e); process.exit(1); });
EOF

# Verify both public endpoints reach 9router
for u in \
  "https://procedures-cool-broken-tenant.trycloudflare.com" \
  "https://rxvudxz.abc-tunnel.us"
do
  code=$(curl -sS --max-time 15 -o /tmp/t-body.txt -w "%{http_code}" "$u/" 2>/dev/null || echo fail)
  echo "$u -> $code"
done

# Check /v1/models with the API key (mask in output later)
KEY=$(node -e "const a=require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js'); a.listApiKeys?0:0" 2>/dev/null)
# use known key from previous call carefully - prefer reading via api again
node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
(async () => {
  const keys = await api.listApiKeys();
  const key = keys.data.keys[0].key;
  const urls = [
    'https://procedures-cool-broken-tenant.trycloudflare.com/v1/models',
    'https://rxvudxz.abc-tunnel.us/v1/models',
    'http://127.0.0.1:20128/v1/models',
  ];
  for (const url of urls) {
    try {
      const res = await fetch(url, { headers: { Authorization: `Bearer ${key}` }, signal: AbortSignal.timeout(15000) });
      const text = await res.text();
      console.log(url, '->', res.status, text.slice(0, 120).replace(/\n/g,' '));
    } catch (e) {
      console.log(url, '-> ERR', e.message);
    }
  }
})();
EOF

# Confirm cloudflared process
pgrep -lf 'cloudflared tunnel' | head -3
lsof -nP -iTCP:20128 -sTCP:LISTEN | head -3

# Check connected providers
node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
(async () => {
  try {
    const res = await api.makeRequest('GET', '/api/providers');
    console.log(JSON.stringify(res, null, 2));
  } catch(e) { console.log('err:', e.message); }
})();
EOF

node <<'EOF'
const api = require('/opt/homebrew/lib/node_modules/9router/src/cli/api/client.js');
async function main() {
  // get providers
  try {
    const res = await api.makeRequest('GET', '/api/providers');
    // Show status for each (quick summary)
    const providers = res.data || [];
    for (const p of providers) {
      console.log(`${p.status || '?'} ${p.id || p.name || '?'}  ${p.description || ''}`);
      if (p.models) console.log('  models:', p.models.slice(0,5).join(', '));
    }
  } catch(e) { console.log('err:', e.message); }
}
main().catch(e => { console.error(e); process.exit(1); });
EOF
